custom_scss:
:root {
  --vt-purple: #6d28d9;
  --vt-indigo: #6366f1;
  --vt-violet: #8b5cf6;
}
.navbar {
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  background: rgba(109, 40, 217, 0.95) !important;
  border-bottom: 1px solid rgba(255,255,255,0.1);
}
.btn-primary {
  background: linear-gradient(135deg, var(--vt-indigo), var(--vt-purple));
  border: none;
  border-radius: 8px;
}
.btn-primary:hover {
  background: linear-gradient(135deg, var(--vt-purple), var(--vt-violet));
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(109, 40, 217, 0.35);
}

theme_scss:
@import url("https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700;800&display=swap");
// backward compatibility. deprecated in v15
$font-family-sans-serif: "Inter", "InterVariable", "Inter", -apple-system, BlinkMacSystemFont,
	"Segoe UI", "Roboto", "Oxygen", "Ubuntu", "Cantarell", "Fira Sans",
	"Droid Sans", "Helvetica Neue", sans-serif;

// override font stack if custom font is set in website theme
:root {
	--font-stack: "Inter", "InterVariable", "Inter", -apple-system, BlinkMacSystemFont,
	"Segoe UI", "Roboto", "Oxygen", "Ubuntu", "Cantarell", "Fira Sans",
	"Droid Sans", "Helvetica Neue", sans-serif !important;
}
$primary: None;$enable-shadows: false;
$enable-gradients: false;
$enable-rounded: true;

